377	    let branch = match &args.branch {
378	        Some(b) => b.clone(),
379	        None => {
380	            let output = Command::new("git")
381	                .args(["rev-parse", "--abbrev-ref", "HEAD"])
382	                .output()
383	                .map_err(|e| format!("Failed to get current branch: {}", e))?;
384	
385	            if !output.status.success() {
386	                return Err("Failed to determine current branch".to_string());
387	            }
388	
389	            String::from_utf8_lossy(&output.stdout).trim().to_string()
390	        }
391	    };
392	
393	    eprintln!("push: pushing {} to {}", branch, args.remote);
394	
395	    let mut push_args = vec!["push", &args.remote, &branch];
