5	//! Notch command - JJ-aware commit with heat/pace context prefix
6	//!
7	//! This module handles the jjx_notch command which performs a staged commit
8	//! with heat/pace context prefix. It accepts explicit file list and generates
9	//! a JJ context-aware commit message.
10	
11	use clap::Args;
12	use std::collections::HashSet;
13	
14	use vvc::{vvco_err, vvco_Output};
15	
16	use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
17	use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
18	
19	const JJRNC_CMD_NAME_RECORD: &str = "jjx_record";
20	
21	/// Arguments for jjx_notch command
22	#[derive(Args, Debug)]
23	pub struct jjrnc_NotchArgs {
24	    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
25	    pub identity: String,
26	
27	    /// Files to commit (required, at least one)
28	    #[arg(required = true)]
29	    pub files: Vec<String>,
30	
31	    /// Size limit in bytes (overrides default 50KB guard)
32	    #[arg(long)]
33	    pub size_limit: Option<u64>,
34	
35	    /// User-provided commit message intent (overrides haiku-generated message)
36	    #[arg(long)]
37	    pub intent: Option<String>,
38	}
39	
40	/// Run the notch command
41	///
42	/// Stages specified files and commits with JJ-aware prefix.
43	/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
44	pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> (i32, String) {
45	    let cn = JJRNC_CMD_NAME_RECORD;
46	    let mut output = vvco_Output::buffer();
47	
48	    // Require non-empty files list
49	    if args.files.is_empty() {
50	        vvco_err!(output, "{}: error: at least one file required", cn);
51	        return (1, output.vvco_finish());
52	    }
53	
54	    // Check each file either exists on disk or is tracked by git (for deletions)
55	    let mut staged_deletions: HashSet<String> = HashSet::new();
56	    for file in &args.files {
57	        let path_exists = std::path::Path::new(file).exists();
58	
59	        // If file doesn't exist on disk, check if it's tracked by git
60	        if !path_exists {
